query:
SELECT COUNT(*) as total_questions FROM questions;
SELECT g.code, g.name, COUNT(q.id) as question_count 
FROM survey_groups g 
LEFT JOIN questions q ON q.group_id = g.id 
GROUP BY g.id, g.code, g.name;
SELECT id, question_text, category, group_id, is_active, created_at 
FROM questions 
ORDER BY created_at DESC 
LIMIT 10;

